func displayEmail(settings models.SettingsPage) string {
	if settings.Email != "" {
		return settings.Email
	}
	if settings.User.Email != "" {
		return settings.User.Email
	}
	return "your account email"
}

func planOrFree(plan string) string {
	if plan == "" {
		return "free"
	}
	return plan
}

